import React, { useState } from 'react';
import LanguageSwitcher from './LanguageSwitcher';

function Swipe({ onProfile, onChat, onFilter, onNotifications, onLogout, onSubscribe, isSubscribed }) {
  const [messagesLeft, setMessagesLeft] = useState(3);
  const [users] = useState([
    { id: 1, name: 'Sarah', age: 24, city: 'Alger', emoji: '👩' },
    { id: 2, name: 'Karim', age: 27, city: 'Oran', emoji: '👨' },
    { id: 3, name: 'Leila', age: 23, city: 'Constantine', emoji: '👩' },
  ]);
  const [index, setIndex] = useState(0);

  const next = () => setIndex((i) => (i + 1) % users.length);

  const handleLike = () => {
    if (messagesLeft <= 0 && !isSubscribed) return alert('💎 Abonnez-vous pour plus de messages');
    setMessagesLeft((m) => m - 1);
    alert(`❤️ Vous avez aimé ${users[index].name}`);
    next();
  };

  return (
    <div style={styles.container}>
      <div style={styles.header}>
        <div style={{ display: 'flex', alignItems: 'center', gap: '10px' }}>
          <h1 style={styles.title}>💕 Chatalgerie</h1>
          <LanguageSwitcher />
        </div>
        <div style={styles.headerRight}>
          <button onClick={onFilter} style={styles.iconBtn}>🔍</button>
          <button onClick={onNotifications} style={styles.iconBtn}>🔔</button>
          <button onClick={onChat} style={styles.iconBtn}>💬</button>
          <button onClick={onProfile} style={styles.iconBtn}>👤</button>
          <button onClick={onLogout} style={styles.iconBtn}>🚪</button>
        </div>
      </div>
      <div style={styles.card}>
        <div style={styles.emoji}>{users[index].emoji}</div>
        <h2>{users[index].name}, {users[index].age}</h2>
        <p>📍 {users[index].city}</p>
        <p style={{ marginTop: 10 }}>💬 {messagesLeft} messages restants</p>
        <div style={styles.actions}>
          <button onClick={next} style={styles.dislikeBtn}>❌</button>
          <button onClick={handleLike} style={styles.likeBtn}>❤️</button>
        </div>
        {!isSubscribed && <button onClick={onSubscribe} style={styles.premiumBtn}>💎 Devenir Premium</button>}
      </div>
    </div>
  );
}

const styles = {
  container: { minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)', padding: 20, display: 'flex', flexDirection: 'column', alignItems: 'center' },
  header: { width: '100%', maxWidth: 400, display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 10 },
  headerRight: { display: 'flex', gap: 8 },
  iconBtn: { background: 'rgba(255,255,255,0.8)', border: 'none', borderRadius: '50%', width: 38, height: 38, fontSize: '1rem', cursor: 'pointer' },
  title: { background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', fontSize: '1.5rem' },
  card: { backgroundColor: 'white', padding: 30, borderRadius: 24, maxWidth: 400, width: '100%', textAlign: 'center', marginTop: 10 },
  emoji: { fontSize: 80 },
  actions: { display: 'flex', justifyContent: 'center', gap: 30, marginTop: 20 },
  dislikeBtn: { background: '#FF6B6B', border: 'none', fontSize: 30, borderRadius: '50%', width: 60, height: 60, cursor: 'pointer' },
  likeBtn: { background: '#FF1493', border: 'none', fontSize: 30, borderRadius: '50%', width: 60, height: 60, cursor: 'pointer' },
  premiumBtn: { marginTop: 20, background: '#FFD700', padding: 12, borderRadius: 12, border: 'none', fontWeight: 'bold', cursor: 'pointer' },
};

export default Swipe;
